    trait SpannedTestUtility<T> {
        fn unwrap_node(self) -> T;
    }

    impl<T> SpannedTestUtility<T> for Spanned<T> {
        fn unwrap_node(self) -> T {
            self.node
        }
    }

    fn sp<T>(node: T) -> Spanned<T> {
        Spanned {
            node,
            span: DUMMY_SPAN,
        }
    }

    fn sp_box<T>(node: T) -> SpannedBox<T> {
        Spanned {
            node: Box::new(node),
            span: DUMMY_SPAN,
        }
    }

    fn eq_expr(a: &Expression, b: &Expression) -> bool {
        use Expression::*;

        match (a, b) {
            (Literal(a), Literal(b)) => a.node == b.node,

            (Path(a), Path(b)) => eq_path(&a.node, &b.node),

            (
                Binary {
                    operator: op1,
                    left: l1,
                    right: r1,
                },
                Binary {
                    operator: op2,
                    left: l2,
                    right: r2,
                },
            ) => op1 == op2 && eq_expr(&l1.node, &l2.node) && eq_expr(&r1.node, &r2.node),

            (
                Assign {
                    operator: op1,
                    left: l1,
                    right: r1,
                },
                Assign {
                    operator: op2,
                    left: l2,
                    right: r2,
                },
            ) => op1 == op2 && eq_expr(&l1.node, &l2.node) && eq_expr(&r1.node, &r2.node),

            (
                Comparison {
                    operator: op1,
                    left: l1,
                    right: r1,
                },
                Comparison {
                    operator: op2,
                    left: l2,
                    right: r2,
                },
            ) => op1 == op2 && eq_expr(&l1.node, &l2.node) && eq_expr(&r1.node, &r2.node),

            (
                Logical {
                    operator: op1,
                    left: l1,
                    right: r1,
                },
                Logical {
                    operator: op2,
                    left: l2,
                    right: r2,
                },
            ) => op1 == op2 && eq_expr(&l1.node, &l2.node) && eq_expr(&r1.node, &r2.node),

            (Array { elements: e1 }, Array { elements: e2 }) => eq_array(e1, e2),

            (
                Call {
                    function: f1,
                    arguments: a1,
                },
                Call {
                    function: f2,
                    arguments: a2,
                },
            ) => {
                eq_expr(&f1.node, &f2.node)
                    && a1.len() == a2.len()
                    && a1.iter().zip(a2).all(|(x, y)| eq_expr(&x.node, &y.node))
            }

            (
                FieldAccess {
                    parent: p1,
                    field_name: f1,
                },
                FieldAccess {
                    parent: p2,
                    field_name: f2,
                },
            ) => f1 == f2 && eq_expr(&p1.node, &p2.node),

            (MethodCall(m1), MethodCall(m2)) => {
                m1.name == m2.name
                    && m1.params.len() == m2.params.len()
                    && m1
                        .params
                        .iter()
                        .zip(&m2.params)
                        .all(|(a, b)| eq_expr(&a.node, &b.node))
            }

            (
                Index {
                    parent: p1,
                    index: i1,
                },
                Index {
                    parent: p2,
                    index: i2,
                },
            ) => eq_expr(&p1.node, &p2.node) && eq_expr(&i1.node, &i2.node),

            (Block(s1), Block(s2)) => {
                s1.len() == s2.len() && s1.iter().zip(s2).all(|(a, b)| eq_stmt(&a.node, &b.node))
            }

            (Loop(l1), Loop(l2)) => eq_loop(&l1.node, &l2.node),

            (
                If {
                    condition: c1,
                    then_body: t1,
                    else_body: e1,
                },
                If {
                    condition: c2,
                    then_body: t2,
                    else_body: e2,
                },
            ) => {
                eq_expr(&c1.node, &c2.node)
                    && eq_expr(&t1.node, &t2.node)
                    && match (e1, e2) {
                        (Some(a), Some(b)) => eq_expr(&a.node, &b.node),
                        (None, None) => true,
                        _ => false,
                    }
            }

            (Continue { label: l1 }, Continue { label: l2 }) => l1 == l2,

            (
                Break {
                    label: l1,
                    expression: e1,
                },
                Break {
                    label: l2,
                    expression: e2,
                },
            ) => {
                l1 == l2
                    && match (e1, e2) {
                        (Some(a), Some(b)) => eq_expr(&a.node, &b.node),
                        (None, None) => true,
                        _ => false,
                    }
            }

            (Return(a), Return(b)) => match (a, b) {
                (Some(a), Some(b)) => eq_expr(&a.node, &b.node),
                (None, None) => true,
                _ => false,
            },

            _ => false,
        }
    }

    fn eq_path(a: &Path, b: &Path) -> bool {
        a.segments.len() == b.segments.len()
            && a.segments.iter().zip(&b.segments).all(|(x, y)| {
                x.node.ident == y.node.ident && x.node.arguments.len() == y.node.arguments.len()
            })
    }

    fn eq_stmt(a: &Statement, b: &Statement) -> bool {
        match (a, b) {
            (Statement::Semicolon, Statement::Semicolon) => true,

            (Statement::Expression(a), Statement::Expression(b)) => eq_expr(&a.node, &b.node),

            (
                Statement::Let {
                    name: n1,
                    initializer: i1,
                    ..
                },
                Statement::Let {
                    name: n2,
                    initializer: i2,
                    ..
                },
            ) => {
                n1.node == n2.node
                    && match (i1, i2) {
                        (Some(a), Some(b)) => eq_expr(&a.node, &b.node),
                        (None, None) => true,
                        _ => false,
                    }
            }

            (Statement::Item(a), Statement::Item(b)) => a.node == b.node,

            _ => false,
        }
    }

    fn eq_loop(a: &LoopExpr, b: &LoopExpr) -> bool {
        match (a, b) {
            (
                LoopExpr::While {
                    condition: c1,
                    body: b1,
                },
                LoopExpr::While {
                    condition: c2,
                    body: b2,
                },
            ) => eq_expr(&c1.node, &c2.node) && eq_expr(&b1.node, &b2.node),

            (
                LoopExpr::For {
                    pattern: p1,
                    iterator: i1,
                    body: b1,
                },
                LoopExpr::For {
                    pattern: p2,
                    iterator: i2,
                    body: b2,
                },
            ) => p1.node == p2.node && eq_expr(&i1.node, &i2.node) && eq_expr(&b1.node, &b2.node),

            (LoopExpr::Loop { body: b1 }, LoopExpr::Loop { body: b2 }) => {
                eq_expr(&b1.node, &b2.node)
            }

            _ => false,
        }
    }

    fn eq_array(a: &ArrayElements, b: &ArrayElements) -> bool {
        match (a, b) {
            (ArrayElements::List(a), ArrayElements::List(b)) => {
                a.len() == b.len() && a.iter().zip(b).all(|(x, y)| eq_expr(&x.node, &y.node))
            }

            (
                ArrayElements::Repeat {
                    value: v1,
                    count: c1,
                },
                ArrayElements::Repeat {
                    value: v2,
                    count: c2,
                },
            ) => eq_expr(&v1.node, &v2.node) && eq_expr(&c1.node, &c2.node),

            _ => false,
        }
    }

    fn int_lit(v: &str) -> Expression {
        Expression::Literal(sp(Literal::Integer {
            value: v.to_string(),
            value_type: TypeKind::Primitive(PrimitiveType::default_integer()),
        }))
    }

    fn ident_expr(name: &str) -> Expression {
        Expression::Path(sp(Path {
            segments: vec![sp(PathSegment {
                ident: name.to_string(),
                arguments: vec![],
            })],
        }))
    }

    fn wrap_fn(src: &str) -> String {
        format!("fn main() {{ {} }}", src)
    }

    fn parse_fn_err(src: &str) {
        parse_err(&wrap_fn(src));
    }

    fn parse_err(src: &str) {
        let result = PackratAndPrattParser::new(tokenize_from_str(src)).parse();
        assert!(
            result.is_err(),
            "expected error but parsed successfully: {}\n{:#?}",
            src,
            result.unwrap()
        );
    }

    // 必ずItemを含む必要がある
    fn parsed_fn(body: &str) -> ASTNode {
        let wrapped_body = wrap_fn(body);
        parsed(&wrapped_body)
    }

    fn extract(node: ASTNode) -> Vec<Statement> {
        let ASTNode::Item { item, .. } = node else {
            panic!();
        };

        let Item::Function { body, .. } = item.node else {
            panic!();
        };

        let body = body.unwrap();

        let Expression::Block(statements) = *body.node else {
            panic!();
        };

        statements.into_iter().map(|s| s.node).collect()
    }

    fn extract_first(node: ASTNode) -> Statement {
        extract(node)[0].clone()
    }

    //
    fn extract_first_expr(node: ASTNode) -> Expression {
        let statement = extract_first(node);
        let Statement::Expression(expr) = statement else {
            panic!("{statement:#?}");
        };

        *expr.node
    }

