    #[test]
    fn test_nested_blocks() {
        let statements = extract(parsed_fn("{{{{{{{{{{{{{{{{}}}}}}}}}}}}}}}}"));
        let mut stack: Vec<&Statement> = statements.iter().collect();

        while let Some(statement) = stack.pop() {
            let Statement::Expression(expr) = statement else {
                panic!("{statement:#?}");
            };
            let Expression::Block(inner_statements) = expr.get_node() else {
                panic!("{statement:#?}");
            };
            stack.extend(inner_statements.iter().map(|s| &s.node));
        }
    }

